+  hidden: {
+    opacity: 0,
+    scale: 0.8,
+  },
+  visible: {
+    opacity: 1,
+    scale: 1,
+    transition: springs.snappy,
+  },
+  exit: {
+    opacity: 0,
+    scale: 0.9,
